/* ====================================================================
   APEX//CONTROL — Tactical HUD  ·  shared helpers (template base CSS)
   --------------------------------------------------------------------
   FULL-TRUST theme (allowUnsafeTemplateContent = true) → raw, unsanitized
   CSS: clip-path (angular notches), @keyframes (scan/pulse), vendor
   prefixes all survive. Brand colors still flow through the live MudBlazor
   palette via rgba(var(--mud-palette-{primary,secondary,tertiary,surface}-rgb), a)
   so every surface auto-adapts to light / dark mode. LED semantics use
   fixed literals (a status light is a status light in either mode).
   ==================================================================== */

/* Condensed industrial wordmark (Bahnschrift ships on Windows; graceful fallback) */
.ax-wordmark {
    font-family: "Bahnschrift", "DIN Condensed", "Roboto Condensed", system-ui, sans-serif;
    font-weight: 700;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--mud-palette-text-primary);
}
.ax-slash { color: rgba(var(--mud-palette-primary-rgb), 1); }

/* Monospace HUD readout */
.ax-mono {
    font-family: "Cascadia Mono", "Consolas", ui-monospace, "SFMono-Regular", monospace;
    letter-spacing: 0.06em;
    font-size: 11px;
    text-transform: uppercase;
}

/* Logo plate: angular notched corner, volt hairline, glowing reticle */
.ax-mark {
    position: relative;
    display: inline-flex; align-items: center; justify-content: center;
    flex: none;
    color: rgba(var(--mud-palette-primary-rgb), 1);
    background:
        linear-gradient(135deg, rgba(var(--mud-palette-primary-rgb), 0.20), rgba(var(--mud-palette-primary-rgb), 0) 60%),
        rgba(var(--mud-palette-surface-rgb), 1);
    border: 1px solid rgba(var(--mud-palette-primary-rgb), 0.55);
    clip-path: polygon(0 0, 100% 0, 100% calc(100% - 9px), calc(100% - 9px) 100%, 0 100%);
    box-shadow: inset 0 0 16px rgba(var(--mud-palette-primary-rgb), 0.20);
}
.ax-mark i { line-height: 1; filter: drop-shadow(0 0 7px rgba(var(--mud-palette-primary-rgb), 0.75)); }

/* Status LED — fixed semantics, glow via box-shadow, optional steady pulse */
.ax-led { width: 9px; height: 9px; border-radius: 50%; display: inline-block; flex: none; }
.ax-led--ok    { background: #2bff88; box-shadow: 0 0 0 3px rgba(43,255,136,0.16),  0 0 10px rgba(43,255,136,0.95); animation: ax-pulse 2.6s ease-in-out infinite; }
.ax-led--warn  { background: #ffc400; box-shadow: 0 0 0 3px rgba(255,196,0,0.16),   0 0 10px rgba(255,196,0,0.95); }
.ax-led--alert { background: #ff5252; box-shadow: 0 0 0 3px rgba(255,82,82,0.16),   0 0 10px rgba(255,82,82,0.95); }

@keyframes ax-pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.4; } }
@keyframes ax-scan  { 0% { top: -2%; opacity: 0; } 12% { opacity: 1; } 88% { opacity: 1; } 100% { top: 102%; opacity: 0; } }
@keyframes ax-boot  { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }
@media (prefers-reduced-motion: reduce) {
    .ax-led--ok, .ax-login__scan, .ax-dh__scan { animation: none !important; }
    .ax-login__panel { animation: none !important; }
}

